import type { ZeroAPISpec } from '../../types/spec.js'

export interface RailwayOptions {
  startCommand?: string
  healthcheckPath?: string
  port?: number
  region?: string
}

/**
 * Generates a railway.toml configuration for deploying on Railway.app.
 */
export function generateRailwayConfig(
  spec: ZeroAPISpec,
  options: RailwayOptions = {}
): string {
  const {
    startCommand = 'node dist/index.js',
    healthcheckPath = '/health',
    port = 3000,
    region = 'us-east',
  } = options

  return `# Generated by @ludagg/zeroapi-runtime for "${spec.name}" v${spec.version}
# Deploy: https://railway.app

[build]
builder = "NIXPACKS"

[deploy]
startCommand = "${startCommand}"
healthcheckPath = "${healthcheckPath}"
healthcheckTimeout = 300
restartPolicyType = "ON_FAILURE"
restartPolicyMaxRetries = 10

[[services]]
internalPort = ${port}
protocol = "TCP"
region = "${region}"

  [[services.ports]]
  port = 80
  handlers = ["http"]

  [[services.ports]]
  port = 443
  handlers = ["tls", "http"]
`
}

/**
 * Returns a Markdown deploy-button badge pointing to the given repository URL.
 */
export function getRailwayDeployButton(repoUrl: string): string {
  const encoded = encodeURIComponent(repoUrl)
  return `[![Deploy on Railway](https://railway.app/button.svg)](https://railway.app/new/template?template=${encoded})`
}
